import React, { useState, useEffect } from 'react'
import { Form, Input, Button, Select, InputNumber, Row, Col, Divider, Space } from 'antd';
import Api from '../../helpers/api';
import { message } from "antd";
import {
    ReloadOutlined,
    ArrowLeftOutlined,
    SaveOutlined,
} from '@ant-design/icons';
import TableParameter from './TableParameter';

const api = new Api();
const { Option } = Select;

const FormParameter = (props) => {

    const [errors, setErrors] = useState({})
    const [loading, setLoading] = useState(false)
    const [type, setType] = useState('')
    const [loadParameters, setLoadParameters] = useState(false)
    const [fieldForm, setFieldForm] = useState({})
    const [form] = Form.useForm();

    useEffect(() => {
        setFieldsForm()
    }, [fieldForm]);

    const onFinish = (data) => {
        setLoading(true)

        let apiPost
        if (props.edit) {
            if (fieldForm) {
                const { id } = fieldForm
                apiPost = api.updateClassificationParameter(id, data)
            } else {
                const { id } = props.match.params
                apiPost = api.storeClassificationParameter(id, data)
            }
        }

        apiPost.then(response => {
            setLoading(false)
            const data = response.data;
            message.success('save data success');

            if (props.add) {
                props.history.push(`/classification-material/edit/${data.id_hash}`);
            } else {
                setLoadParameters(true)
                handleReset()
            }
        }).catch(error => {
            setLoading(false)
            if (error.response && error.response.data) {
                const { errors } = error.response.data
                setErrors(errors)
            }
        });
    };

    const setFieldsForm = () => {
        const { name, type, length, value, decimal } = fieldForm
        setType(type)
        form.setFieldsValue({
            parameter_name: name,
            type,
            length,
            value,
            decimal,
        });
    }

    const handleReset = () => {
        form.setFieldsValue({
            parameter_name: '',
            type: '',
            length: '',
            value: '',
            decimal: '',
        });
        setType('')
    }

    const onSelectType = (value) => {
        setType(value)
    }

    const handleEditParameter = (value) => {
        setFieldForm(value)
    }

    return (
        <Form name="complex-form" onFinish={onFinish} labelCol={{ span: 4 }} wrapperCol={{ span: 8 }}
            form={form}>

            <Row>
                <Col xs={24} sm={24} md={24} lg={10} xl={10}>
                    <Form.Item name="parameter_name" label="Field Name"
                        validateStatus={errors && errors.parameter_name ? 'error' : undefined}
                        help={errors ? errors.parameter_name : null}
                        rules={[{ required: true, message: 'Please input field name' }]}>
                        <Input />
                    </Form.Item>

                    <Form.Item name="type" label="Type"
                        validateStatus={errors && errors.type ? 'error' : undefined}
                        help={errors ? errors.type : null}
                        rules={[{ required: true, message: 'Please select type' }]}>
                        <Select
                            onChange={onSelectType} value={type}>
                            <Option value={1}>Text</Option>
                            <Option value={2}>Date</Option>
                            <Option value={3}>Time</Option>
                            <Option value={4}>Numeric</Option>
                            <Option value={5}>Select Option</Option>
                        </Select>
                    </Form.Item>

                    { // Length
                        type === 1 || type === 4 ?
                            <Form.Item name="length" label="Length"
                                validateStatus={errors && errors.length ? 'error' : undefined}
                                help={errors ? errors.length : null}
                                rules={[{ required: true, message: 'Please input length' }]}>
                                <InputNumber
                                    className="mnd-input-number"
                                    min={0}
                                    formatter={value => `${value}`.replace(/\B(?=(\d{3})+(?!\d))/g, ',')}
                                    parser={value => value.replace(/\$\s?|(,*)/g, '')} />
                            </Form.Item> : null
                    }

                    { // Decimal
                        type === 4 ?
                            < Form.Item name="decimal" label="Decimal"
                                validateStatus={errors && errors.decimal ? 'error' : undefined}
                                help={errors ? errors.decimal : null}
                                rules={[{ required: true, message: 'Please input decimal' }]}>
                                <InputNumber
                                    className="mnd-input-number"
                                    min={0}
                                    formatter={value => `${value}`.replace(/\B(?=(\d{3})+(?!\d))/g, ',')}
                                    parser={value => value.replace(/\$\s?|(,*)/g, '')} />
                            </Form.Item> : null}

                    { // List
                        type === 5 ?
                            <Form.Item name="value" label="Value"
                                validateStatus={errors && errors.value ? 'error' : undefined}
                                help={errors ? errors.value : null}
                                rules={[{ required: true, message: 'Please input value' }]}>
                                <Input placeholder='Separate with ","' />
                            </Form.Item> : null}
                </Col>

                {/* List parameters */}
                <Col xs={24} sm={24} md={24} lg={14} xl={14}>
                    <TableParameter {...props}
                        loadParameters={loadParameters}
                        setLoadParameters={(value) => setLoadParameters(value)}
                        editParameter={handleEditParameter} />
                </Col>
            </Row>

            <p><span style={{ color: '#f5222d', fontSize: 14 }}>*</span> Required</p>
            <Divider />

            <Form.Item>
                <Space>
                    <Button onClick={() => props.history.push('/classification-material/list')}
                        icon={<ArrowLeftOutlined />}
                    >Back</Button>

                    {props.view ?? (
                        <>
                            <Button onClick={() => handleReset()}
                                icon={<ReloadOutlined />}
                            >Reset</Button>

                            <Button
                                type="primary"
                                htmlType="submit"
                                loading={loading}
                                icon={<SaveOutlined />}
                            >Save</Button>
                        </>
                    )}
                </Space>
            </Form.Item>
        </Form >
    )
}

export default FormParameter;