import React, { useState, useEffect } from 'react'
import { Form, Input, Button, Divider, Space } from 'antd';
import Api from '../../helpers/api';
import { message } from "antd";
import {
    ReloadOutlined,
    ArrowLeftOutlined,
    SaveOutlined,
} from '@ant-design/icons';
import handleApiError from '../../helpers/handleApiError';

const api = new Api();

const FormClassification = (props) => {

    const [errors, setErrors] = useState({})
    const [loading, setLoading] = useState(false)
    const [form] = Form.useForm();

    useEffect(() => {
        const { view, edit } = props
        if (view || edit) {
            getEditData()
        }
    }, []);

    const onFinish = (data) => {
        setLoading(true)

        let apiPost
        //handling if form add
        if (props.add) {
            apiPost = api.storeClassificationMaterial(data)
        } else if (props.edit) {
            //handling if form edit
            const { id } = props.match.params
            apiPost = api.storeClassificationParameter(id, data)
        }

        apiPost.then(response => {
            setLoading(false)
            const data = response.data;
            message.success('save data success');

            if (props.add) {
                props.history.push(`/classification-material/edit/${data.id_hash}`);
            }
        }).catch(error => {
            setLoading(false)
            if (error.response && error.response.data) {
                const { errors } = error.response.data
                setErrors(errors)
            }
        });
    };

    const getEditData = () => {
        const { id } = props.match.params

        api.viewClassificationMaterial(id)
            .then(response => {
                const { name } = response.data
                form.setFieldsValue({ name });
            }).catch(error => {
                handleApiError(error, props)
            })
    }

    const handleReset = () => {
        form.setFieldsValue({
            name: '',
        });
    }

    return (
        <Form name="complex-form" onFinish={onFinish} labelCol={{ span: 4 }} wrapperCol={{ span: 8 }}
            form={form}>
            <Form.Item name="name" label="Name"
                validateStatus={errors && errors.name ? 'error' : undefined}
                help={errors ? errors.name : null}
                rules={[{ required: true, message: 'Please input name' }]}>
                <Input />
            </Form.Item>

            <p><span style={{ color: '#f5222d', fontSize: 14 }}>*</span> Required</p>
            <Divider />

            <Form.Item>
                <Space>
                    <Button onClick={() => props.history.push('/classification-material/list')}
                        icon={<ArrowLeftOutlined />}
                    >Back</Button>

                    {props.view ?? (
                        <>
                            <Button onClick={() => handleReset()}
                                icon={<ReloadOutlined />}
                            >Reset</Button>

                            <Button
                                type="primary"
                                htmlType="submit"
                                loading={loading}
                                icon={<SaveOutlined />}
                            >Save</Button>
                        </>
                    )}
                </Space>
            </Form.Item>
        </Form>
    )
}

export default FormClassification;