import React, { useState, useEffect } from 'react'
import { Card, Tabs } from 'antd';
import FormParameter from './FormParameter';
import FormClassification from './FormClassification';

const { TabPane } = Tabs;

const FormPage = (props) => {
    const [activeTab, setActiveTab] = useState(1)

    useEffect(() => {
        const { add, edit } = props
        if (edit) {
            setActiveTab(2)
        }
    }, []);

    const onTabClick = (key) => {
        setActiveTab(key)
    }

    return (
        <Card>
            <Tabs defaultActiveKey="1" activeKey={`${activeTab}`} onChange={onTabClick}>
                <TabPane tab="Classification" key="1">
                    <FormClassification {...props} />
                </TabPane>
                <TabPane tab="Fields" key="2" disabled={props.add ?? false}>
                    <FormParameter {...props} />
                </TabPane>
            </Tabs>
        </Card >
    )
}

export default FormPage;