import React, { Component } from 'react'
import { Button, message, Table, Menu, Dropdown, Modal, Col, Row } from 'antd';
import Api from '../../helpers/api';
import {
  DeleteOutlined,
  EllipsisOutlined,
  EditOutlined
} from '@ant-design/icons';

const api = new Api();

export class TableParameter extends Component {
  constructor(props) {
    super(props)
    this.state = {
      data: [],
      visible: false,
      created_by: {},
      updated_by: {},
    }
  }

  componentDidMount() {
    this.fetch()
  }

  componentWillReceiveProps(nextProps) {
    if (nextProps.loadParameters) {
      nextProps.setLoadParameters(false)
      this.fetch()
    }
  }

  fetch = () => {
    // console.log('params:', params);
    const { view, edit, match } = this.props
    // console.log(this.props)
    let id

    if (view || edit) {
      id = match.params.id
    }

    this.setState({ loading: true });

    api.viewClassificationMaterial(id)
      .then(response => {
        // console.log('view classification material',response.data);
        const data = response.data;
        // const pagination = { ...this.state.pagination };

        // pagination.current = data.current_page
        // pagination.total = data.total;
        // pagination.pageSize = parseInt(data.per_page);

        if (response.status === 200) { //OK

          let parameters = [];
          if (data.parameters.length > 0) {
            parameters = data.parameters.sort(function (a, b) { return b.id - a.id; });
          }

          this.setState({
            loading: false,
            data: parameters,
            // pagination,
          })
        }
      })
      .catch(() => {
        this.setState({ loading: false });
      })

  }

  //more action button
  handleMenuClick(e, record) {
    const { id } = record

    switch (e.key) {
      case "edit":
        this.props.editParameter(record)
        break;
      case "change-log":
        this.showModal(id)
        break;
      case "delete":
        this.confirmDeleteData(id)
        break;
      default:
        break;
    }
  }

  showModal = (id) => {
    api.viewLocationType(id)
      .then(response => {
        // console.log(response.data)
        const data = response.data
        this.setState({ ...data })
      })
      .catch(error => {
        // console.log(error)
      })

    this.setState({
      visible: true,
    });
  }

  //oke handle in modal
  handleOk = (e) => {
    // console.log(e);
    this.setState({
      visible: false,
    });
  }

  //cancel handle in modal
  handleCancel = (e) => {
    // console.log(e);
    this.setState({
      visible: false,
    });
  }

  confirmDeleteData(id) {
    Modal.confirm({
      title: 'Are you sure delete this data?',
      okText: 'Yes',
      okType: 'danger',
      cancelText: 'No',
      onOk: () => {
        this.deleteData(id)
      },
      onCancel: () => {
        // console.log('Cancel');
      },
    });
  }

  deleteData(id) {
    api.deleteClassificationParameter(id)
      .then(() => {
        message.success('Delete data success');
        this.fetch();
      })
      .catch(error => {
        // console.log(error.response)
        message.error('Failed to delete');
        //   handleApiError(error)
      })
  }

  render() {
    //this is for modal
    const { created_at, updated_at, created_by, updated_by } = this.state
    const labelCol = {
      xs: { span: 24 },
      sm: { span: 16 },
      md: { span: 8 },
    }
    const wrapperCol = {
      xs: { span: 24 },
      sm: { span: 16 },
      md: { span: 8 },
    }
    //this is parameter table column
    const columns = [
      {
        title: 'ID',
        dataIndex: 'id',
        width: 30
      },
      {
        title: 'Field Name',
        dataIndex: 'name',
        width: 100
      },
      {
        title: 'Type',
        dataIndex: 'type',
        width: 30,
        render: (type) => {
          switch (type) {
            case 1:
              return "Text"
            case 2:
              return "Date"
            case 3:
              return "Time"
            case 4:
              return "Numeric"
            case 5:
              return "List"
            default:
              return null
          }
        }
      },
      {
        title: 'Length',
        dataIndex: 'length',
        className: 'col-number',
        width: 30
      },
      {
        title: 'Decimal',
        dataIndex: 'decimal',
        className: 'col-number',
        width: 30
      },
      {
        title: 'Value',
        dataIndex: 'value',
        width: 100
      },
      // {
      //   title: 'Reading',
      //   dataIndex: 'reading_indicator',
      //   render: (value) => (value ? 'Yes' : 'No'),
      //   width: 30
      // },
      {
        title: '',
        render: (record) => {
          // if (this.props.view) { return null }
          return (
            <div>
              <Dropdown overlay={(
                <Menu onClick={e => this.handleMenuClick(e, record)}>
                  <Menu.Item key="edit"><EditOutlined /> Edit</Menu.Item>
                  {/* <Menu.Item key="change-log"><Icon type="file-done" />Change Log</Menu.Item> */}
                  <Menu.Item key="delete"><DeleteOutlined style={{ color: 'red' }} /> <span style={{ color: 'red' }}>Delete</span></Menu.Item>
                </Menu>
              )}>
                <Button size="small"><EllipsisOutlined /> </Button>
              </Dropdown>
            </div>
          )
        },
        width: 30,
        fixed: 'right'
      }
    ]


    return (
      <div>
        <Table
          columns={columns}
          rowKey={record => record.id}
          dataSource={this.state.data}
          pagination={false}
          loading={this.state.loading}
          scroll={{ y: 300, x: 1000 }}
        />

        <Modal
          title="Change Log"
          visible={this.state.visible}
          onOk={this.handleOk}
          onCancel={this.handleCancel}
          footer={null}
        >
          <Row style={styles.row}><Col {...labelCol}>Created at</Col><Col {...wrapperCol}>{created_at}</Col></Row>
          <Row style={styles.row}><Col {...labelCol}>Updated at</Col><Col {...wrapperCol}>{updated_at}</Col></Row>
          <Row style={styles.row}><Col {...labelCol}>Created by</Col><Col {...wrapperCol}>{created_by.name}</Col></Row>
          <Row style={styles.row}><Col {...labelCol}>Updated by</Col><Col {...wrapperCol}>{updated_by ? updated_by.name : '-'}</Col></Row>
        </Modal>
      </div>
    )
  }
}

const styles = {
  //modal
  row: {
    margin: '10px 0',
  }
}

export default TableParameter